                  <Icons.Chat />
                </div>
                <h4 className="font-bold text-slate-900 mb-2">Welcome to EstatePro</h4>
                <p className="text-slate-500 text-sm max-w-[240px] mx-auto leading-relaxed">I can assist with property details, neighborhood insights, or scheduling a viewing.</p>
              </div>
            )}
            {messages.map((m) => (
              <div key={m.id} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
